### barnsley_j1_gpu.frag
#include <flutter/runtime_effect.glsl>
// Barnsley J1: piecewise linear  (Mandelbrot-style, z₀=0, c=pixel)
//   z_{n+1} = (z−1)·c   if Re(z) ≥ 0
//   z_{n+1} = (z+1)·c   if Re(z) < 0
// Discovered by Michael Barnsley; produces pointed, bird-wing-shaped attractors.
// Derivative (dz/dc): exact piecewise product rule, der₀=(0,0).
//   derNew = c·der + (z±1)  (branch treated as locally constant)
// Supports normal-map shading (colorScheme 50-63).
uniform float uTime;          // 0
uniform vec2  uResolution;    // 1-2
uniform vec2  uCenter;        // 3-4
uniform float uZoom;          // 5
uniform float uIterations;    // 6
uniform float uBailout;       // 7
uniform float uColorScheme;   // 8
uniform float uTransparentBg; // 9
// IEC 61966-2-1 sRGB transfer function (linear → display-encoded).
// colorScheme 0-49: standard palette. 50-63: normal-map (14 angles × 4 palettes).

