### sierpinski_julia_rational_gpu.frag
#include <flutter/runtime_effect.glsl>
// Sierpinski-Julia Rational Map: z → z² + c/z²
// Julia sets homeomorphic to Sierpinski gaskets via Misiurewicz-type rational maps.
// The rational singularity at z=0 creates carpet/gasket-like structures at
// critical c values, producing fractal boundaries with Sierpinski topology.
// Derivative (Julia-style dz/dz₀):
//   f(z) = z² + c/z²
//   f'(z) = 2z − 2c/z³
//   derNew = f'(z) · der, der₀ = (1,0)
// Supports normal-map shading (colorScheme 50-63).
uniform float uTime;          // 0
uniform vec2  uResolution;    // 1-2
uniform vec2  uCenter;        // 3-4
uniform float uZoom;          // 5
uniform float uIterations;    // 6
uniform float uBailout;       // 7
uniform float uColorScheme;   // 8
