from pathlib import Path
import re, collections
root=Path('shaders/ifs_and_geometric')
func_re=re.compile(r'^(?:float|vec[234]|mat[234]|int|bool)\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(')
by_func=collections.defaultdict(list)
for p in sorted(root.rglob('*.frag')):
    for line in p.read_text(errors='ignore').splitlines():
        m=func_re.match(line.strip())
        if m:
            by_func[m.group(1)].append(str(p))
for name, paths in sorted(by_func.items(), key=lambda kv:(-len(kv[1]), kv[0])):
    if len(paths) >= 10:
        dirs=sorted(set(Path(x).parent.name for x in paths))
        print(f'{name}: {len(paths)} files across {len(dirs)} dirs ({", ".join(dirs)})')
PY
